    var oldGen = typeof topic.gen === 'function' ? topic.gen : (fnName && typeof window[fnName] === 'function' ? window[fnName] : null);
    var nextGen = mergeGen(oldGen, rows, topic, subj);
    topic.gen = nextGen;
    if (fnName) window[fnName] = nextGen;
