      var fnMap = {
        letters:'genLetters',
        syllable:'genSyllable',
        jishi:'genJishi',
        capital:'genCapital',
        conj:'genConj'
      };
      var topic = expandTopic(subj, topicId, data.expand[topicId] || [], fnMap[topicId] || null);
